import{_ as e,o as d,c as r,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/images/uebung049.jpg",c=JSON.parse('{"title":"Übung Lektion 31","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung31.md","filePath":"lektionen/uebung31.md"}'),a={name:"lektionen/uebung31.md"};function s(o,t,h,l,u,b){return d(),r("div",null,[...t[0]||(t[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-31" tabindex="-1">Übung Lektion 31 <a class="header-anchor" href="#ubung-lektion-31" aria-label="Permalink to &quot;Übung Lektion 31&quot;">​</a></h1><p>A) Übersetzen Sie folgende Sätze und lösen Sie die Komposita auf:</p><p>प्रज्ञा दुःखसम्भवं रुन्ध्यादिति बुद्धिमानार्यबुद्धमार्गेण गच्छेत् ॥१॥ दुःखस्य सम्भवम् । आर्येण बुद्धस्य / बुद्धानां मार्गेण । Damit Einsicht die Entstehung von Leid verhindert, soll ein vernünftiger Mensch den edlen Weg Buddhas / der Buddhas gehen. ... geht ein vernünftiger Mensch den edlen Weg Buddhas / der Buddhas.</p><p>शस्त्राणि शरीरमेव छिन्दन्ति जीवस्तु न म्रियत इति भगव्द्गीतायां भगवतोच्यते ॥२॥ भगवतो गीतायाम् Der Ehrwürdige sagt in der Bhagavadgītā,, dass Schwerter nur den Körper spalten, die Seele aber nicht stirbt.</p><p>बुद्ध्या युक्तो दुःखान्मुच्यते तस्मान्मोक्षमिच्छन्नरो योगेन युञ्जीत ॥३॥ Wer Einsicht hat, wird vom Leiden befreit; deshalb soll jemand, der Erlösung wünscht, sich durch Yoga anstrengen und konzentrieren.</p><p>पुत्रो जातो बन्धनं जातमिति सुगतो मत्वा कुलबन्धनं भिनत्ति । ततो भग्नबन्धो मोक्षनयन्तीं प्रज्ञामाप्तुमर्हति ॥४॥ कुलस्य बन्धनम् । भग्नो बन्धो येन सः । मोक्षं नयन्तीम् । &quot;Ein Sohn ist mir geboren - eine Fessel ist geboren&quot; mit diesem Gedanken zerreißt der erfolgreich den Weg durch die Wiedergeburten Gegangene die Bindung an die Familie. Nachdem er die Bande zerrissen hat kann er die zur Erlösung führende Einsicht erreichen.</p><p>समोहः स्वन्नानि च सुरूपाश्च भुङ्क्ते वीतमोहस्त्वन्नं च सम्पन्नरूपशरीरां च न लुभ्यति । स हि लोभं च क्रोधं च रुणद्धि प्रज्ञायां च युङ्क्ते ॥५॥ मोहेन सहितः । शोभनं रूपं यासां ताः । वीतो मोहो यस्य सः । सम्पन्नं रूपं यस्य स शारीरो यास्यास्ताम् । Ein Verblendester genießt gute Speisen und schöne Frauen. Wessen Verblendung verschwunden ist, begehrt keine gute Speise und keine Frau mit vollkommenem Körper. Er verhindert nämlich Gier und Hass und konzentriert sich auf die Einsicht.</p><p>B) Bilden Sie zu folgenden Wurzeln der 7. Klasse alle 3. Personen Singular und Plural, P und Ā, des Indikativ und Optativ Präsens:</p><p>१. छिद्</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>लट्</td><td>छिनत्ति</td><td>छिन्दन्ति</td></tr><tr><td>विधिलिङ्</td><td>छिन्द्यात्</td><td>छिन्द्युर्</td></tr></tbody></table></blockquote><p>२. भिद्</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>लट्</td><td>भिनत्ति</td><td>भिन्दन्ति</td></tr><tr><td>विधिलिङ्</td><td>भिन्द्यात्</td><td>भिन्द्युर्</td></tr></tbody></table></blockquote><p>३. भुज्</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>लट्</td><td>भुनक्ति</td><td>भुञ्जन्ति</td></tr><tr><td>विधिलिङ्</td><td>भुञ्ज्यात्</td><td>भुञ्ज्युर्</td></tr></tbody></table></blockquote><p>४. अञ्ज् (nur P)</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>लट्</td><td>अनक्ति</td></tr><tr><td>विधिलिङ्</td><td>अञ्ज्यात्</td></tr></tbody></table></blockquote><p>५. भञ्ज् (nur P)</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td></td><td>एकवचनम्</td></tr><tr><td>लट्</td><td>भनक्ति</td></tr><tr><td>विधिलिङ्</td><td>भञ्ज्यात्</td></tr></tbody></table></blockquote><p><img src="'+i+'" alt=""><br> Abb.: कुलबन्धनम्<br> [Bildquelle: Carol Mitchell. -- <a href="http://www.flickr.com/photos/webethere/2171088197/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/webethere/2171088197/</a>. -- Zugriff am 2009-01-05. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative commons Lizenz (Namensnennung, keine Bearbeitung)]</p>',20)])])}const g=e(a,[["render",s]]);export{c as __pageData,g as default};
